from dataclasses import dataclass
from typing import Any

@dataclass
class EntityResolutionResult:
    mdm_id: str | None
    confidence: float          # 0.0–1.0
    entity_domain: str
    matched_aliases: list[str] # The user-supplied strings that were matched
    ambiguous: bool            # True if multiple candidates scored similarly

class EntityResolver:
    """Resolve natural-language entity references to MDM canonical IDs."""

    def __init__(self, mdm_hub, alias_index):
        self.mdm_hub = mdm_hub
        # alias_index maps normalized alias -> list of (mdm_id, entity_domain)
        self.alias_index = alias_index

    def resolve(self, mention: str, entity_domain: str | None = None) -> EntityResolutionResult:
        normalized = mention.lower().strip()
        candidates = self.alias_index.lookup(normalized, domain=entity_domain)

        if not candidates:
            return EntityResolutionResult(
                mdm_id=None, confidence=0.0,
                entity_domain=entity_domain or "unknown",
                matched_aliases=[], ambiguous=False,
            )

        # Exact match
        if len(candidates) == 1:
            mdm_id, domain = candidates[0]
            return EntityResolutionResult(
                mdm_id=mdm_id, confidence=1.0,
                entity_domain=domain,
                matched_aliases=[mention], ambiguous=False,
            )

        # Multiple candidates: score by alias specificity and return ambiguous flag
        top = candidates[0]
        runner_up = candidates[1]
        ambiguous = (top.score - runner_up.score) < 0.2  # margin too small
        return EntityResolutionResult(
            mdm_id=top.mdm_id if not ambiguous else None,
            confidence=top.score,
            entity_domain=top.domain,
            matched_aliases=[mention],
            ambiguous=ambiguous,
        )

from typing import Any

INTENT_FIELD_MAP: dict[str, list[str]] = {
    "price_inquiry":    ["list_price", "discount_policy", "currency", "effective_date"],
    "availability":     ["stock_qty", "lead_time_days", "warehouse_locations"],
    "product_details":  ["description", "technical_specs", "certifications"],
    "contact_lookup":   ["email", "phone", "office_location", "job_title"],
    "policy_query":     ["content", "effective_date", "expiry_date", "owner"],
    "default":          [],  # Empty means serialize all attributes
}

def serialize_golden_record_for_prompt(
    golden_record,
    query_intent: str,
    max_chars: int = 1200,
) -> str:
    field_subset = INTENT_FIELD_MAP.get(query_intent, INTENT_FIELD_MAP["default"])
    if field_subset:
        attrs = {k: v for k, v in golden_record.attributes.items() if k in field_subset}
    else:
        attrs = golden_record.attributes

    lines = [
        f"[ENTITY: {golden_record.entity_domain.upper()}]",
        f"canonical_id: {golden_record.mdm_id}",
        f"version: {golden_record.version}  "
        f"(as of {golden_record.updated_at.strftime('%Y-%m-%d')})",
        "---",
    ]
    for attr, value in attrs.items():
        source = golden_record.attribute_sources.get(attr, "?")
        lines.append(f"{attr}: {value}  [src: {source}]")

    serialized = "\n".join(lines)
    if len(serialized) > max_chars:
        serialized = serialized[:max_chars] + "\n[...truncated]\n"
    return serialized

from datetime import datetime, timedelta, timezone
from dataclasses import dataclass, field

@dataclass
class CachedGoldenRecord:
    record: object                   # GoldenRecord instance
    fetched_at: datetime
    ttl_seconds: int = 300           # Default 5-minute TTL

    def is_expired(self) -> bool:
        age = (datetime.now(timezone.utc) - self.fetched_at).total_seconds()
        return age > self.ttl_seconds

class SessionGoldenRecordCache:
    def __init__(self, mdm_hub):
        self.mdm_hub = mdm_hub
        self._cache: dict[str, CachedGoldenRecord] = {}

    def get(self, mdm_id: str, ttl_seconds: int = 300):
        if mdm_id in self._cache:
            cached = self._cache[mdm_id]
            if not cached.is_expired():
                # Version check: if MDM hub has a newer version, invalidate
                current_version = self.mdm_hub.get_current_version(mdm_id)
                if current_version == cached.record.version:
                    return cached.record
        # Cache miss or stale: fetch fresh
        record = self.mdm_hub.get_golden_record(mdm_id)
        self._cache[mdm_id] = CachedGoldenRecord(
            record=record,
            fetched_at=datetime.now(timezone.utc),
            ttl_seconds=ttl_seconds,
        )
        return record

    def invalidate(self, mdm_id: str) -> None:
        self._cache.pop(mdm_id, None)
